import crypto from 'node:crypto';

import env from 'frontend-env';

import { readAppPackageField, readFuryAppName } from './fs';
import { NordicEnvError } from './error';

function getAppValue({
  nordicVersion,
  key,
  value,
}: {
  nordicVersion: string;
  key: string;
  value?: string;
}) {
  const finalValue = value || readAppPackageField(key);

  if (!finalValue && nordicVersion) {
    throw new NordicEnvError(
      `Application ${key} is required,` +
        ` make sure it is set in the "${key}" environment variable` +
        ` or "${key}" field in the \`package.json\` file.`,
    );
  }

  return finalValue;
}

export function getAppName(nordicVersion: string) {
  const { APPLICATION, npm_package_name: pkgName } = env;

  return getAppValue({
    nordicVersion,
    value: APPLICATION || readFuryAppName() || pkgName,
    key: 'name',
  });
}

export function getAppNameHash(appName: string) {
  return appName && crypto.hash('md5', appName, 'base64url');
}

export function getAppVersion(nordicVersion: string) {
  const { VERSION, npm_package_version: pkgVersion } = env;

  return getAppValue({
    nordicVersion,
    value: VERSION || pkgVersion,
    key: 'version',
  });
}
